import re
from ag2 import register_message_hook

def code_safety_hook(message):
    if 'code' in message.role.lower():
        dangerous_patterns = [
            r'rm\s+-rf',
            r'del\s+/f\s+/s',
            r'shutdown',
            r'format\s+c:',
            r'exec\(input\(',
        ]

        for pattern in dangerous_patterns:
            if re.search(pattern, message.content, re.IGNORECASE):
                return {
                    'content': f"🚫 Code blocked: Contains dangerous pattern '{pattern}'. Please rewrite safely.",
                    'role': 'SAFETY'
                }
    return message

# Apply to all coding agents
for agent in coding_agents:
    agent.register_message_hook(code_safety_hook)
